class Solution {
    public int countKReducibleNumbers(String s, int k) {
        long n = Long.parseLong(s, 2);
        int count = 0;
        for (long i = 1; i < n; i++) {
            int setBits = Integer.bitCount((int) i);
            if (isKReducible(i, k)) {
                count++;
            }
        }
        return (int) (count % (1000000007));
    }
    private boolean isKReducible(long num, int k) {
        int setBits = Integer.bitCount((int) num);
        while (k > 0 && setBits > 1) {
            num = setBits;
            setBits = Integer.bitCount((int) num);
            k--;
        }
        return setBits == 1;
    }
}
